if (! function_exists('tool_to_markdown')) {
    function tool_to_markdown($path, $title = null, $include_code = null, $output_file = null, $timeout = null)
    {
        // Auto-documentation generator - reads PHP tool source, produces Markdown docs
        // Uses tokenizer to extract docblocks, function signatures, params, returns

        $path = isset($path) ? (string)$path : '';
        $title = isset($title) ? (string)$title : '';
        $include_code = isset($include_code) ? (bool)$include_code : false;
        $output_file = isset($output_file) ? (string)$output_file : '';

        if ($path === '') return ['error' => 'Path to PHP tool file is required'];

        // Resolve path
        $full_path = realpath($path);
        if ($full_path === false || !file_exists($full_path)) {
            $project_root = realpath(__DIR__ . '/../../..');
            $full_path = realpath($project_root . '/' . ltrim($path, '/'));
        }
        if ($full_path === false || !file_exists($full_path)) {
            return ['error' => "File not found: {$path}"];
        }

        $source = @file_get_contents($full_path);
        if ($source === false) return ['error' => 'Cannot read file'];

        try {
            $tokens = token_get_all($source);
            
            // Extract info
            $tool_name = '';
            $description = '';
            $params = [];
            $returns = '';
            $full_docblock = '';
            $in_docblock = false;
            $in_function = false;
            $function_body = '';
            $function_start = -1;
            $brace_depth = 0;
            
            $i = 0;
            $count = count($tokens);
            
            // Phase 1: Find the function definition and its docblock
            while ($i < $count) {
                $token = $tokens[$i];
                
                // Look for function keyword
                if (is_array($token) && $token[0] === T_FUNCTION) {
                    // Found a function - check if it's the tool function (not a closure)
                    $next_idx = $i + 1;
                    while ($next_idx < $count && is_array($tokens[$next_idx]) && in_array($tokens[$next_idx][0], [T_WHITESPACE, T_COMMENT])) {
                        $next_idx++;
                    }
                    
                    if ($next_idx < $count && is_array($tokens[$next_idx]) && $tokens[$next_idx][0] === T_STRING) {
                        $found_name = $tokens[$next_idx][1];
                        
                        // Look backwards for a docblock
                        $lookback = $i - 1;
                        $docblock = '';
                        while ($lookback >= 0) {
                            $prev = $tokens[$lookback];
                            if (is_array($prev)) {
                                if ($prev[0] === T_DOC_COMMENT) {
                                    $docblock = $prev[1];
                                    break;
                                } elseif ($prev[0] === T_WHITESPACE) {
                                    $lookback--;
                                    continue;
                                } else {
                                    break;
                                }
                            } else {
                                break;
                            }
                        }
                        
                        $full_docblock = $docblock;
                        $tool_name = $found_name;
                        $function_start = $i;
                        
                        // Extract params from signature
                        $sig_start = $next_idx + 1;
                        $depth = 0;
                        $sig_text = '';
                        for ($j = $sig_start; $j < $count; $j++) {
                            $t = $tokens[$j];
                            $str = is_array($t) ? $t[1] : $t;
                            $sig_text .= $str;
                            if ($str === '(') $depth++;
                            elseif ($str === ')') { $depth--; if ($depth === 0) break; }
                        }
                        
                        // Parse signature for params
                        // Extract everything between ( and )
                        $paren_start = strpos($sig_text, '(');
                        $paren_end = strrpos($sig_text, ')');
                        if ($paren_start !== false && $paren_end !== false) {
                            $params_str = substr($sig_text, $paren_start + 1, $paren_end - $paren_start - 1);
                            $param_parts = explode(',', $params_str);
                            foreach ($param_parts as $part) {
                                $part = trim($part);
                                if ($part === '' || $part === '...') continue;
                                
                                // Extract default value
                                $default = null;
                                $eq_pos = strpos($part, '=');
                                if ($eq_pos !== false) {
                                    $default = trim(substr($part, $eq_pos + 1));
                                    $part = trim(substr($part, 0, $eq_pos));
                                }
                                
                                // Parse "type $name" or "$name"
                                $parts = preg_split('/\s+/', $part);
                                if (count($parts) >= 2) {
                                    $type = $parts[0];
                                    $name = ltrim(end($parts), '$');
                                } else {
                                    $type = 'mixed';
                                    $name = ltrim($parts[0], '$');
                                }
                                
                                $params[] = [
                                    'name' => $name,
                                    'type' => $type,
                                    'default' => $default,
                                    'required' => $default === null,
                                ];
                            }
                        }
                        
                        // Extract return type (PHP 7+ style)
                        $return_search = $sig_text;
                        $arrow_pos = strrpos($return_search, ':');
                        if ($arrow_pos !== false) {
                            $ret_type = trim(substr($return_search, $arrow_pos + 1));
                            // Clean up
                            $ret_type = preg_replace('/[(){};]/', '', $ret_type);
                            $returns = $ret_type;
                        }
                        
                        break; // Found the first function - that's our tool
                    }
                }
                $i++;
            }
            
            // Phase 2: Extract description from docblock
            $description = '';
            if ($full_docblock !== '') {
                // Remove /** */ markers and leading *
                $lines = explode("\n", $full_docblock);
                $desc_lines = [];
                $in_long_desc = false;
                foreach ($lines as $line) {
                    $clean = preg_replace('/^\\s*\\/?\\*\\*?\\s?/', '', $line);
                    $clean = trim($clean);
                    if ($clean === '') continue;
                    if (str_starts_with($clean, '@')) break; // Stop at annotations
                    if ($clean !== '/') {
                        $desc_lines[] = $clean;
                    }
                }
                $description = implode(' ', $desc_lines);
            }
            
            // Phase 3: Parse @param and @return annotations from docblock
            $param_docs = [];
            $return_doc = '';
            if ($full_docblock !== '') {
                preg_match_all('/@param\\s+(\\S+)\\s+\\$(\\S+)\\s*(.*?)$/m', $full_docblock, $pm, PREG_SET_ORDER);
                foreach ($pm as $m) {
                    $param_docs[$m[2]] = ['type' => $m[1], 'desc' => trim($m[3] ?? '')];
                }
                preg_match('/@return\\s+(\\S+)\\s*(.*?)$/m', $full_docblock, $rm);
                if ($rm) {
                    $return_doc = $rm[1] . ($rm[2] ? ' - ' . trim($rm[2]) : '');
                }
            }
            
            // Phase 4: Build usage examples
            $usage_examples = [];
            $version_info = '';
            $author = '';
            $extensions = [];
            
            if ($full_docblock !== '') {
                preg_match('/@version\\s+(.+)$/m', $full_docblock, $vm);
                if ($vm) $version_info = trim($vm[1]);
                preg_match('/@author\\s+(.+)$/m', $full_docblock, $am);
                if ($am) $author = trim($am[1]);
            }
            
            // Check tool definition JSON for parameters schema
            $tool_definition = null;
            if (preg_match('/\\$toolDefinition_' . preg_quote($tool_name, '/') . '\\s*=\\s*(\\[.*?\\]);/s', $source, $tm)) {
                $tool_definition = @eval("return {$tm[1]};");
            }
            
            // Build Markdown
            $markdown = '';
            
            // Title
            $display_title = $title ?: "Tool: `{$tool_name}`";
            $markdown .= "# {$display_title}\n\n";
            
            // Description
            if ($description !== '') {
                $markdown .= "## Description\n\n{$description}\n\n";
            }
            
            // File info
            $file_size = filesize($full_path);
            $rel_path = str_replace(realpath(__DIR__ . '/../../..') . '\\', '', $full_path);
            $markdown .= "## File Info\n\n";
            $markdown .= "- **File**: `{$rel_path}`\n";
            $markdown .= "- **Size**: " . ($file_size >= 1024 ? round($file_size/1024, 1) . ' KB' : $file_size . ' B') . "\n";
            $markdown .= "- **Function**: `{$tool_name}()`\n";
            if ($version_info) $markdown .= "- **Version**: {$version_info}\n";
            if ($author) $markdown .= "- **Author**: {$author}\n";
            $markdown .= "\n";
            
            // Parameters
            if (count($params) > 0) {
                $markdown .= "## Parameters\n\n";
                $markdown .= "| Parameter | Type | Required | Default | Description |\n";
                $markdown .= "|-----------|------|----------|---------|-------------|\n";
                
                foreach ($params as $param) {
                    $type = isset($param_docs[$param['name']]['type']) ? $param_docs[$param['name']]['type'] : $param['type'];
                    $desc = isset($param_docs[$param['name']]['desc']) ? $param_docs[$param['name']]['desc'] : '';
                    $required = $param['required'] ? 'Yes' : 'No';
                    $default = $param['default'] ?? '';
                    $markdown .= "| `{$param['name']}` | `{$type}` | {$required} | `{$default}` | {$desc} |\n";
                }
                $markdown .= "\n";
            }
            
            // Return type
            if ($returns !== '' || $return_doc !== '') {
                $markdown .= "## Returns\n\n";
                $rt = $return_doc ?: $returns;
                $markdown .= "`{$rt}`\n\n";
            }
            
            // Source
            if ($include_code) {
                $markdown .= "## Source Code\n\n```php\n{$source}\n```\n";
            }
            
            // Write output
            if ($output_file !== '') {
                $workspace = realpath(__DIR__ . '/../../workspace');
                $out_path = $workspace . '/' . ltrim($output_file, '/');
                file_put_contents($out_path, $markdown);
            }
            
            return [
                'success' => true,
                'tool_name' => $tool_name,
                'source_file' => $rel_path,
                'file_size' => $file_size,
                'description' => $description,
                'parameters' => $params,
                'return_type' => $returns ?: ($return_doc ?: 'none declared'),
                'has_docblock' => $full_docblock !== '',
                'param_count' => count($params),
                'markdown_length' => strlen($markdown),
                'markdown_preview' => substr($markdown, 0, 500),
                'output_file' => $output_file ?: null,
            ];
            
        } catch (\Throwable $e) {
            return ['error' => 'Documentation generation failed: ' . $e->getMessage()];
        }
    }
